import axios, { AxiosInstance, CreateAxiosDefaults } from "axios";
import FormData from "form-data";
import { createRequire } from 'module'
const require = createRequire(import.meta.url);
const cheerio = require("cheerio")

interface Webp2Mp4Options {
    axiosInstance?: AxiosInstance;
    timeout?: number;
    headers?: Record<string, string>;
}

async function PNGToPdf(imageUrls: string[] = []): Promise<any> {
  const api: AxiosInstance = axios.create({
    headers: {
      'User-Agent': 'Mozilla/5.0 (Linux; Android 12; V2111) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/140.0 Mobile Safari/537.36',
      'origin': 'https://www.freepdfconvert.com',
      'referer': 'https://www.freepdfconvert.com/ar/jpg-to-pdf',
      'accept-language': 'ar-EG,ar;q=0.9,en-US;q=0.8,en;q=0.7'
    }
  });

  const ids: string[] = [];
  for (const url of imageUrls) {
    const res = await api.get(url, { responseType: 'arraybuffer' });
    const buffer = Buffer.from(res.data, 'binary');
    const data = new FormData();
    data.append('file', buffer, { filename: 'image.jpg' });
    const upload = await api.post<any>('https://www.freepdfconvert.com/upload', data, {
      headers: data.getHeaders()
    });
    ids.push(upload.data.FileId);
  }

  const pdfIds: string[] = [];
  for (const id of ids) {
    const data = JSON.stringify({
      Parameters: [
        {
          Name: 'File',
          FileValues: null,
          FileValue: { Name: null, Data: null, Id: id },
          Value: null
        }
      ]
    });

    const convert = await api.post<any>(
      'https://www.freepdfconvert.com/convert/jpg/to/pdf?StoreFile=true&timeOut=1200&PageOrientation=default&MarginHorizontal=&MarginVertical=&PageSize=default&stamp=true',
      data,
      { headers: { 'Content-Type': 'application/json' } }
    );

    pdfIds.push(convert.data.Files[0].FileId);
  }

  const mergeData = JSON.stringify({
    Parameters: [
      {
        Name: 'Files',
        FileValues: pdfIds.map(id => ({ Name: null, Data: null, Id: id })),
        FileValue: null,
        Value: null
      }
    ]
  });

  const merged = await api.post<any>(
    'https://www.freepdfconvert.com/convert/pdf/to/merge?StoreFile=true&stamp=true',
    mergeData,
    { headers: { 'Content-Type': 'application/json' } }
  );

  return merged.data;
}

/* webp to mp4 */
async function WebpToMp4(
    source: string | Buffer, 
    options: Webp2Mp4Options = {}
): Promise<string> {
    
    const defaultConfig: CreateAxiosDefaults = {
        timeout: options.timeout || 30000,
        headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
            ...options.headers
        },
        maxContentLength: Infinity,
        maxBodyLength: Infinity
    };

    const client = options.axiosInstance || axios.create(defaultConfig);
    
    let form = new FormData();
    let isUrl = typeof source === 'string' && /https?:\/\//.test(source);
    
    form.append('new-image-url', isUrl ? source : '');
    form.append('new-image', isUrl ? '' : source, 'image.webp');
    
    try {
        let res = await client.post('https://ezgif.com/webp-to-mp4', form, {
            headers: { ...form.getHeaders() }
        });
        
        let html = res.data;
        let $ = cheerio.load(html);
        let form2 = new FormData();
        let obj: { [key: string]: string } = {};
        
        $('form input[name]').each((index: number, el: any) => {
            obj[$(el).attr('name')!] = $(el).val() as string;
            form2.append($(el).attr('name')!, $(el).val() as string);
        });
        
        let res2 = await client.post('https://ezgif.com/webp-to-mp4/' + obj.file, form2, {
            headers: { ...form2.getHeaders() }
        });
        
        let html2 = res2.data;
        let $2 = cheerio.load(html2);
        
        const videoSrc = $2('div#output > p.outfile > video > source').attr('src');
        if (!videoSrc) {
            throw new Error('No results found');
        }
        
        return new URL(videoSrc, res2.config.url).toString();
    } catch (error: any) {
        throw new Error(error.message);
    }
}


const Convert = { PNGToPdf, WebpToMp4 };
export default Convert;