import { proto, WAMessage } from "@whiskeysockets/baileys";
import { msgObj } from "../r-enhancers/index.js";
import { print } from "../utils/index.js";

type MsgUpsert = { messages: proto.IWebMessageInfo[]; type: string };

const objs = {
  isValid: (m: proto.IWebMessageInfo) => {
    if (!m.message) return false;
    return !(m.message.protocolMessage || m.message.senderKeyDistributionMessage || m.message.stickerSyncRmrMessage);
  },
  ignore: (m: any) => m?.key?.id?.includes("3EB0") || false,
  autoRead: async (ctx: any, m: proto.IWebMessageInfo) => {
    if (ctx.config?.autoRead) try { await ctx.sock.readMessages([m.key]); } catch {}
  },
  fromMeCheck: (ctx: any, m: any) => {
    if (ctx.config?.fromMe === true && !m.fromMe) return false;
    if (ctx.config?.fromMe === false && m.fromMe) return false;
    return true;
  },
  runHandlers: async (m: any, ctx: any) => {
    if (!ctx.handlers?.length) return false;
    for (const h of ctx.handlers) {
      try {
        const res = await h(m);
        if (!res) continue;
        if (typeof res === 'string') await m.reply(res);
        else if (typeof res === 'object' && res.text) await m.reply(res.text, res);
        return true;
      } catch (e) { ctx.config?.onError?.(e); }
    }
    return false;
  },
  process: async (ctx: any, m: proto.IWebMessageInfo) => {
    if (!objs.isValid(m)) return;
    await objs.autoRead(ctx, m);
    const msg = await msgObj(m as WAMessage, ctx.sock, ctx.config?.owners, ctx);
    if (!msg) return;
    if (!objs.fromMeCheck(ctx, msg)) return;
    if (objs.ignore(msg)) return;
    const done = await ctx.commandSystem.processMessage(msg, ctx, ctx.config?.prefix || '');
    if (!done) await objs.runHandlers(msg, ctx);
  },
  create: (withPrint: boolean) => (ctx: any) => {
    if (!ctx?.sock) return;
    let ready = false;
    setTimeout(() => { ready = true; }, 5000);

    ctx.sock.ev.on('messages.upsert', async ({ messages, type }: MsgUpsert) => {
      if (!ready) return;
      if (type !== 'notify') return;
      if (withPrint) print(messages, ctx);
      for (const m of messages) {
        try { await objs.process(ctx, m); }
        catch (e) { ctx.config?.onError?.(e); }
      }
    });
  }
};

export const message_event = objs.create(true);
export const sub_event = objs.create(false);