import { readdir, stat } from 'fs/promises';
import { pathToFileURL, fileURLToPath } from 'url';
import { createRequire } from 'module';
import { resolve, join, dirname, isAbsolute, extname } from 'path';
import { Message, CommandOptions } from "../types/types.js";
import { extractPrefix } from './prefix.js';
import { watch, FSWatcher } from 'chokidar';
import { existsSync } from 'fs';
import { cmdControl } from "../control/index.js";
import { UI } from "../utils/index.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

type Handler = (msg: Message, ctx: any, bot?: any) => Promise<boolean | void>;
type Middleware = (msg: Message, next: () => Promise<void>) => Promise<void>;
type CommandModule = CommandOptions | CommandOptions[] | Handler;

const ALL_PROPS = [
  'command', 'name', 'description', 'aliases', 'category', 'usage',
  'owner', 'group', 'private', 'botAdmin', 'admin',
  'cooldown', 'disabled', 'usePrefix', 'noSub', 'hidden',
  'before', 'after'
];

const VALID_EXTENSIONS = ['js', 'ts', 'mjs', 'cjs'];

const sharedLoadedPaths = new Set<string>();
let globalWatcherStarted = false;
let globalWatcher: any = null;
let globalWatcherPath = '';

const errorStore: { command: string; file: string; error: string; time: string }[] = [];

const errorCmd = {
  get: () => [...errorStore],
  clear: () => { errorStore.length = 0; },
  getByCommand: (commandName: string) => errorStore.filter(e => e.command === commandName),
  getByFile: (fileName: string) => errorStore.filter(e => e.file.includes(fileName)),
  getLast: (count: number = 10) => errorStore.slice(0, count)
};

function logError(error: Error, commandName: string, filePath: string): void {
  errorStore.unshift({
    command: commandName,
    file: filePath,
    error: error.message,
    time: new Date().toISOString()
  });

  if (errorStore.length > 100) {
    errorStore.pop();
  }

  UI.error(`[${new Date().toLocaleTimeString()}] Error in command "${commandName}": ${error.message}`);
  UI.line();
}

class CooldownManager {
  private cache = new Map<string, number>();

  set(key: string): void { this.cache.set(key, Date.now()); }
  clear(key?: string): void { key ? this.cache.delete(key) : this.cache.clear(); }

  getRemaining(key: string, cooldown: number): number {
    const lastUsed = this.cache.get(key);
    if (!lastUsed) return 0;
    const remaining = Math.ceil(cooldown - (Date.now() - lastUsed) / 1000);
    return remaining > 0 ? remaining : 0;
  }

  destroy(): void { this.cache.clear(); }
}

class CommandRegistry {
  private commands = new Map<string, CommandOptions>();
  private nameIndex = new Map<string, string>();
  private aliasIndex = new Map<string, string>();
  private regexCommands: Array<{ id: string; pattern: RegExp }> = [];
  private categoryIndex = new Map<string, Set<string>>();
  private fileIndex = new Map<string, Set<string>>();
  private beforeHookIndex = new Set<string>();
  private hiddenCommands = new Set<string>();
  private noSubCommands = new Set<string>();

  register(command: CommandOptions, filePath?: string): string {
    const id = this.generateId(command);
    this.commands.set(id, command);

    const cmdField = command.command;
    if (cmdField instanceof RegExp) {
      this.regexCommands.push({ id, pattern: cmdField });
    } else {
      for (const name of this.getCommandNames(command)) {
        this.nameIndex.set(name.toLowerCase(), id);
      }
    }

    if (command.aliases) {
      for (const alias of command.aliases) this.aliasIndex.set(alias.toLowerCase(), id);
    }

    if (command.category) {
      if (!this.categoryIndex.has(command.category)) this.categoryIndex.set(command.category, new Set());
      this.categoryIndex.get(command.category)!.add(id);
    }

    if (filePath) {
      const np = resolve(filePath);
      if (!this.fileIndex.has(np)) this.fileIndex.set(np, new Set());
      this.fileIndex.get(np)!.add(id);
    }

    if (command.before) this.beforeHookIndex.add(id);
    if (command.hidden) this.hiddenCommands.add(id);
    if (command.noSub === true) this.noSubCommands.add(id);

    return id;
  }

  findByName(name: string, isOwner = false, isSubBot = false): { command: CommandOptions; isBlockedForSubBot: boolean } | undefined {
    const n = name.toLowerCase();
    const id = this.nameIndex.get(n) || this.aliasIndex.get(n);

    if (id) {
      const cmd = this.commands.get(id);
      if (cmd) {
        if (isSubBot && this.noSubCommands.has(id)) {
          return { command: cmd, isBlockedForSubBot: true };
        }
        if (!this.hiddenCommands.has(id) || isOwner) {
          return { command: cmd, isBlockedForSubBot: false };
        }
      }
    }

    for (const { id, pattern } of this.regexCommands) {
      if (pattern.test(name)) {
        const cmd = this.commands.get(id);
        if (cmd) {
          if (isSubBot && this.noSubCommands.has(id)) {
            return { command: cmd, isBlockedForSubBot: true };
          }
          if (!this.hiddenCommands.has(id) || isOwner) {
            return { command: cmd, isBlockedForSubBot: false };
          }
        }
      }
    }

    return undefined;
  }

  findByCategory(category: string, isOwner = false): CommandOptions[] {
    const ids = this.categoryIndex.get(category);
    if (!ids) return [];
    const result: CommandOptions[] = [];
    for (const id of ids) {
      if (!this.hiddenCommands.has(id) || isOwner) {
        const cmd = this.commands.get(id);
        if (cmd) result.push(cmd);
      }
    }
    return result;
  }

  findByFile(filePath: string): CommandOptions[] {
    const ids = this.fileIndex.get(resolve(filePath));
    if (!ids) return [];
    const result: CommandOptions[] = [];
    for (const id of ids) {
      const cmd = this.commands.get(id);
      if (cmd) result.push(cmd);
    }
    return result;
  }

  getCommandsWithBeforeHooks(isOwner = false): CommandOptions[] {
    const result: CommandOptions[] = [];
    for (const id of this.beforeHookIndex) {
      if (!this.hiddenCommands.has(id) || isOwner) {
        const cmd = this.commands.get(id);
        if (cmd) result.push(cmd);
      }
    }
    return result;
  }

  unregister(name: string): boolean {
    const id = this.nameIndex.get(name.toLowerCase());
    if (!id) return false;
    const cmd = this.commands.get(id);
    if (!cmd) return false;

    this.commands.delete(id);
    this.beforeHookIndex.delete(id);
    this.hiddenCommands.delete(id);
    this.noSubCommands.delete(id);

    for (const n of this.getCommandNames(cmd)) this.nameIndex.delete(n.toLowerCase());
    if (cmd.aliases) for (const a of cmd.aliases) this.aliasIndex.delete(a.toLowerCase());
    this.regexCommands = this.regexCommands.filter(r => r.id !== id);

    if (cmd.category) {
      const catSet = this.categoryIndex.get(cmd.category);
      if (catSet) {
        catSet.delete(id);
        if (catSet.size === 0) this.categoryIndex.delete(cmd.category);
      }
    }

    return true;
  }

  unregisterByFile(filePath: string): void {
    const np = resolve(filePath);
    const ids = this.fileIndex.get(np);
    if (!ids) return;

    for (const id of ids) {
      const cmd = this.commands.get(id);
      if (cmd) {
        for (const n of this.getCommandNames(cmd)) this.nameIndex.delete(n.toLowerCase());
        if (cmd.aliases) for (const a of cmd.aliases) this.aliasIndex.delete(a.toLowerCase());

        if (cmd.category) {
          const catSet = this.categoryIndex.get(cmd.category);
          if (catSet) {
            catSet.delete(id);
            if (catSet.size === 0) this.categoryIndex.delete(cmd.category);
          }
        }
      }
      this.commands.delete(id);
      this.beforeHookIndex.delete(id);
      this.hiddenCommands.delete(id);
      this.noSubCommands.delete(id);
      this.regexCommands = this.regexCommands.filter(r => r.id !== id);
    }
    this.fileIndex.delete(np);
  }

  getAll(isOwner = false, isSubBot = false): CommandOptions[] {
    const result: CommandOptions[] = [];
    for (const [id, cmd] of this.commands) {
      if (isSubBot && this.noSubCommands.has(id)) continue;
      if (!this.hiddenCommands.has(id) || isOwner) {
        result.push(cmd);
      }
    }
    return result;
  }

  getAllCategories(): string[] {
    return [...this.categoryIndex.keys()];
  }

  getStats() {
    return {
      total: this.commands.size,
      hidden: this.hiddenCommands.size,
      noSub: this.noSubCommands.size,
      categories: this.categoryIndex.size,
      files: this.fileIndex.size,
      regexCommands: this.regexCommands.length
    };
  }

  private generateId(command: CommandOptions): string {
    const names = this.getCommandNames(command);
    const base = names[0]?.toLowerCase() || (command.command instanceof RegExp ? command.command.source : 'unknown');
    if (!this.commands.has(base)) return base;
    let i = 1;
    while (this.commands.has(`${base}_${i}`)) i++;
    return `${base}_${i}`;
  }

  private getCommandNames(command: CommandOptions): string[] {
    const names: string[] = [];
    if (command.command && !(command.command instanceof RegExp)) {
      const cmdNames = Array.isArray(command.command) ? command.command : [command.command];
      names.push(...cmdNames);
    }
    if (command.name) names.push(command.name);
    return names;
  }
}

class MiddlewareChain {
  private middlewares: Middleware[] = [];

  use(middleware: Middleware): this { this.middlewares.push(middleware); return this; }

  async run(msg: Message, final: () => Promise<void>): Promise<void> {
    let index = 0;
    const next = async (): Promise<void> => {
      if (index < this.middlewares.length) {
        await this.middlewares[index++](msg, next);
      } else {
        await final();
      }
    };
    await next();
  }

  clear(): void { this.middlewares = []; }
  get length(): number { return this.middlewares.length; }
}

class CommandExecutor {
  private cooldownManager = new CooldownManager();

  async execute(cmd: CommandOptions, msg: Message, context: any, bot: any, filePath?: string): Promise<boolean> {
    if (!await this.checkConditions(cmd, msg, bot, context.isSubBot)) return false;
    if (!await this.checkCooldown(cmd, msg, bot)) return false;

    try {
      const result = await cmd.execute!(msg, context, bot);
      if (cmd.cooldown) {
        const key = this.getCooldownKey(msg, cmd);
        this.cooldownManager.set(key);
      }
      return result !== false;
    } catch (error: any) {
      logError(error, cmd.command?.toString() || 'unknown', filePath || (cmd as any).__filePath || 'unknown');
      return false;
    }
  }

  getCooldownManager(): CooldownManager { return this.cooldownManager; }

  private async checkConditions(cmd: CommandOptions, msg: Message, bot: any, isSubBot: boolean): Promise<boolean> {
    if (cmd.disabled) { await cmdControl(bot, msg, 'disabled'); return false; }
    if (cmd.noSub === true && isSubBot) { await cmdControl(bot, msg, 'noSub'); return false; }
    if (cmd.owner && !msg.isOwner) { await cmdControl(bot, msg, 'owner'); return false; }
    if (cmd.group && !msg.isGroup) { await cmdControl(bot, msg, 'group'); return false; }
    if (cmd.admin && !msg.isAdmin) { await cmdControl(bot, msg, 'admin'); return false; }
    if (cmd.private && msg.isGroup) { await cmdControl(bot, msg, 'private'); return false; }
    if (cmd.botAdmin && !msg.isBotAdmin) { await cmdControl(bot, msg, 'botAdmin'); return false; }
    return true;
  }

  private async checkCooldown(cmd: CommandOptions, msg: Message, bot: any): Promise<boolean> {
    if (!cmd.cooldown) return true;
    const key = this.getCooldownKey(msg, cmd);
    const remaining = this.cooldownManager.getRemaining(key, cmd.cooldown);
    if (remaining > 0) {
      await cmdControl(bot, msg, 'cooldown', remaining);
      return false;
    }
    return true;
  }

  private getCooldownKey(msg: Message, cmd: CommandOptions): string {
    const cmdName = cmd.command instanceof RegExp
      ? cmd.command.source
      : Array.isArray(cmd.command) ? cmd.command[0] : cmd.command || 'unknown';
    return `${msg.sender}:${cmdName}`;
  }

  destroy(): void { this.cooldownManager.destroy(); }
}

class CommandFileWatcher {
  private watcher: FSWatcher | null = null;
  private watchedPath = '';
  private debounceTimers = new Map<string, NodeJS.Timeout>();
  private reloadQueue = new Set<string>();
  private processingReload = false;

  constructor(private readonly onFileChange: (path: string, event: 'add' | 'change' | 'unlink') => Promise<void>) {}

  start(commandsPath: string): void {
    if (globalWatcherStarted && globalWatcherPath === commandsPath) return;
    this.stop();

    const absolutePath = this.resolvePath(commandsPath);
    this.watchedPath = absolutePath;

    if (!existsSync(absolutePath)) {
      UI.error(`Path does not exist: ${absolutePath}`);
      return;
    }

    const isAndroid = process.platform === 'android' || !!(process as any).env.TERMUX_VERSION;
    const isWindows = process.platform === 'win32';
    const pollingConfig = (isAndroid || isWindows)
      ? { usePolling: true, interval: isAndroid ? 1500 : 500, binaryInterval: isAndroid ? 2000 : 1000 }
      : { usePolling: false };

    globalWatcher = watch(absolutePath, {
      ignored: [/(^|[\/\\])\../, /node_modules/, /\.git/],
      persistent: true,
      ignoreInitial: true,
      depth: 99,
      awaitWriteFinish: { stabilityThreshold: 500, pollInterval: 100 },
      ...pollingConfig
    });

    globalWatcherPath = absolutePath;
    globalWatcherStarted = true;
    this.watcher = globalWatcher;

    this.watcher
      ?.on('ready', () => {
        UI.done('Watcher ready and monitoring changes');
      })
      .on('add', p => {
        UI.info(`[FILE ADDED] ${p}`);
        this.debounce(p, 'add');
      })
      .on('change', p => {
        UI.info(`[FILE CHANGED] ${p}`);
        this.debounce(p, 'change');
      })
      .on('unlink', p => {
        UI.info(`[FILE DELETED] ${p}`);
        this.debounce(p, 'unlink');
      })
      .on('error', (e: any) => {
        UI.error(`Watcher error: ${e.message}`);
        UI.line();
      });
  }

  stop(): void {
    if (this.watcher === globalWatcher && globalWatcherStarted) return;
    if (this.watcher && this.watcher !== globalWatcher) {
      this.watcher.close();
      this.watcher = null;
    }
    this.debounceTimers.forEach(t => clearTimeout(t));
    this.debounceTimers.clear();
    this.reloadQueue.clear();
  }

  static stopGlobalWatcher(): void {
    if (globalWatcher) {
      globalWatcher.close();
      globalWatcher = null;
      globalWatcherStarted = false;
      globalWatcherPath = '';
      UI.info('Global watcher stopped');
      UI.line();
    }
  }

  private debounce(path: string, event: 'add' | 'change' | 'unlink'): void {
    const ext = extname(path).toLowerCase().slice(1);
    if (!VALID_EXTENSIONS.includes(ext)) return;

    const existing = this.debounceTimers.get(path);
    if (existing) clearTimeout(existing);

    const timer = setTimeout(async () => {
      this.debounceTimers.delete(path);
      this.reloadQueue.add(path);

      if (!this.processingReload) {
        await this.processReloadQueue(event);
      }
    }, 300);

    this.debounceTimers.set(path, timer);
  }

  private async processReloadQueue(event: 'add' | 'change' | 'unlink'): Promise<void> {
    if (this.processingReload) return;
    this.processingReload = true;

    try {
      const paths = Array.from(this.reloadQueue);
      this.reloadQueue.clear();

      for (const path of paths) {
        try {
          await this.onFileChange(path, event);

          if (event === 'add') {
            UI.done(`✓ Command file loaded: ${path}`);
          } else if (event === 'change') {
            UI.done(`✓ Command file reloaded: ${path}`);
          } else if (event === 'unlink') {
            UI.done(`✓ Command file unloaded: ${path}`);
          }
          UI.line();
        } catch (error: any) {
          UI.error(`Failed to process ${path}: ${error.message}`);
          UI.line();
        }
      }
    } finally {
      this.processingReload = false;
    }
  }

  private resolvePath(givenPath: string): string {
    if (isAbsolute(givenPath)) return givenPath;
    const candidates = [resolve(process.cwd(), givenPath), resolve(__dirname, givenPath)];
    for (const p of candidates) { if (existsSync(p)) return p; }
    return resolve(process.cwd(), givenPath);
  }
}

class CommandLoader {
  private require = createRequire(import.meta.url);
  private cache = new Map<string, { module: any; timestamp: number }>();

  async loadFile(filePath: string, forceReload: boolean = false): Promise<CommandModule | null> {
    try {
      const normalizedPath = resolve(filePath);

      if (forceReload) {
        this.clearModuleCache(normalizedPath);
      }

      const stats = await stat(normalizedPath);
      const cached = this.cache.get(normalizedPath);

      if (!forceReload && cached && cached.timestamp === stats.mtimeMs) {
        return cached.module;
      }

      const ext = extname(normalizedPath).toLowerCase().slice(1);
      const exported = await this.importModule(normalizedPath, ext);
      const normalized = this.normalizeExports(exported, normalizedPath);

      if (normalized) {
        this.cache.set(normalizedPath, { module: normalized, timestamp: stats.mtimeMs });
      }

      return normalized;
    } catch (error: any) {
      UI.error(`Failed to load ${filePath}: ${error.message}`);
      UI.line();
      return null;
    }
  }

  clearCache(filePath?: string): void {
    if (filePath) {
      const normalizedPath = resolve(filePath);
      this.cache.delete(normalizedPath);
      this.clearModuleCache(normalizedPath);
    } else {
      this.cache.clear();
    }
  }

  private clearModuleCache(filePath: string): void {
    const normalizedPath = resolve(filePath);
    delete this.require.cache[normalizedPath];
  }

  private async importModule(filePath: string, ext: string): Promise<any> {
    if (ext === 'cjs') {
      delete this.require.cache[resolve(filePath)];
      try {
        return this.require(filePath);
      } catch {}
    }

    const fileUrl = pathToFileURL(filePath).href;
    const uniqueUrl = `${fileUrl}?t=${Date.now()}&r=${Math.random()}`;
    return await import(uniqueUrl);
  }

  private normalizeExports(exported: any, filePath: string): CommandModule | null {
    if (!exported) return null;
    const moduleExports = exported.default ?? exported;

    if (Array.isArray(moduleExports)) {
      const result: CommandModule[] = [];
      for (const item of moduleExports) {
        const normalized = this.normalizeExports(item, filePath);
        if (normalized) result.push(normalized);
      }
      return result as CommandOptions[];
    }
    if (typeof moduleExports === 'function') return this.normalizeFunction(moduleExports, filePath);
    if (typeof moduleExports === 'object') return this.normalizeObject(moduleExports, filePath);
    return null;
  }

  private normalizeFunction(fn: any, filePath: string): CommandModule {
    const ext = extname(filePath).toLowerCase().slice(1);
    if (fn.name === 'before' || fn.name === 'after') {
      return Object.assign(fn, { __filePath: filePath, __loader: ext });
    }
    const cmd: CommandOptions = { execute: fn };
    for (const prop of ALL_PROPS) {
      if (fn[prop] !== undefined) (cmd as any)[prop] = fn[prop];
    }
    for (const key of Object.keys(fn)) {
      if (!ALL_PROPS.includes(key) && key !== 'execute') (cmd as any)[key] = fn[key];
    }
    return Object.assign(cmd, { __filePath: filePath, __loader: ext });
  }

  private normalizeObject(obj: any, filePath: string): CommandModule | null {
    if (obj.execute && typeof obj.execute === 'function') return this.attachFilePath(obj, filePath);
    const fnKeys = Object.keys(obj).filter(k => typeof obj[k] === 'function' && !['constructor', 'toString', 'valueOf'].includes(k));
    if (fnKeys.length === 1) {
      const cmd = { ...obj, execute: obj[fnKeys[0]] };
      delete cmd[fnKeys[0]];
      return this.attachFilePath(cmd, filePath);
    }
    return null;
  }

  private attachFilePath(obj: any, filePath: string): any {
    obj.__filePath = filePath;
    obj.__loader = extname(filePath).toLowerCase().slice(1);
    return obj;
  }
}

export class CommandSystem {
  private registry: CommandRegistry;
  private middleware: MiddlewareChain;
  private executor: CommandExecutor;
  private loader: CommandLoader;
  private watcher: CommandFileWatcher;
  private beforeHandlers: Handler[] = [];
  private afterHandlers: Handler[] = [];
  public bot: any;
  private instanceId: string;
  private watcherStarted = false;

  constructor(bot?: any) {
    this.bot = bot;
    this.instanceId = Math.random().toString(36).substring(7);
    this.registry = new CommandRegistry();
    this.middleware = new MiddlewareChain();
    this.executor = new CommandExecutor();
    this.loader = new CommandLoader();
    this.watcher = new CommandFileWatcher(this.handleFileChange.bind(this));
  }

  setBot(bot: any): void { this.bot = bot; }

  register(command: CommandOptions | Function): void {
    let cmdObj: CommandOptions;
    if (typeof command === 'function') {
      cmdObj = { execute: command as any };
      for (const prop of ALL_PROPS) {
        if ((command as any)[prop] !== undefined) (cmdObj as any)[prop] = (command as any)[prop];
      }
    } else {
      cmdObj = { ...command };
    }
    this.registry.register(cmdObj, (cmdObj as any).__filePath);
  }

  unregister(commandName: string): boolean { return this.registry.unregister(commandName); }
  before(handler: Handler): void { this.beforeHandlers.push(handler); }
  after(handler: Handler): void { this.afterHandlers.push(handler); }
  use(middleware: Middleware): void { this.middleware.use(middleware); }

  findCommand(name: string, isOwner = false, isSubBot = false): CommandOptions | undefined {
    const result = this.registry.findByName(name, isOwner, isSubBot);
    return result?.command;
  }

  getCommandsByCategory(category?: string, isOwner = false, isSubBot = false): CommandOptions[] {
    return category ? this.registry.findByCategory(category, isOwner) : this.registry.getAll(isOwner, isSubBot);
  }

  getAllCategories(): string[] { return this.registry.getAllCategories(); }
  getAll(isOwner = false, isSubBot = false): CommandOptions[] { return this.registry.getAll(isOwner, isSubBot); }

  async processMessage(msg: Message, ctx: any, config: any): Promise<boolean> {
    if (!msg.body) return false;

    const isSubBot = ctx.isSubBot === true || ctx.constructor?.name === 'SubBot';
    const finalIsSubBot = isSubBot;

    const participants = await this.getGroupParticipants(msg, ctx);

    const context: any = {
      conn: ctx.sock,
      text: msg.body,
      args: [],
      command: '',
      prefix: '',
      bot: ctx,
      Api: ctx.Api,
      isOwner: msg.isOwner,
      isAdmin: msg.isAdmin,
      isGroup: msg.isGroup,
      isBotAdmin: msg.isBotAdmin,
      isSubBot: finalIsSubBot,
      participants: participants
    };

    const shouldStop = await this.runBeforeHandlers(msg, context);
    if (shouldStop) return true;

    for (const cmd of this.registry.getCommandsWithBeforeHooks(msg.isOwner || false)) {
      try {
        const result = await (cmd.before as any)(msg, context, ctx);
        if (result === true) return true;
      } catch (error: any) {
        UI.error(`Command before hook error: ${error.message}`);
        UI.line();
      }
    }

    const text = msg.body.trim();
    const prefixes = config || ["."];
    const extracted = extractPrefix(text, prefixes);

    if (extracted) {
      const findResult = this.registry.findByName(extracted.command, msg.isOwner || false, finalIsSubBot);
      
      if (!findResult) {
        return false;
      }
      
      const { command: cmd, isBlockedForSubBot } = findResult;
      
      if (isBlockedForSubBot) {
        await cmdControl(ctx, msg, 'noSub');
        return true;
      }
      
      if (!cmd?.execute) return false;

      const cmdContext: any = {
        ...context,
        text: extracted.args.join(' '),
        args: extracted.args,
        command: extracted.command,
        prefix: extracted.prefix
      };

      let executed = false;
      await this.middleware.run(msg, async () => {
        executed = await this.executor.execute(cmd, msg, cmdContext, ctx, (cmd as any).__filePath);
      });

      if (executed) {
        if (cmd.after) {
          try { await (cmd.after as any)(msg, cmdContext, ctx); }
          catch (error: any) {
            UI.error(`Command after hook error: ${error.message}`);
            UI.line();
          }
        }
        await this.runAfterHandlers(msg, extracted, cmdContext, ctx);
      }

      return executed;
    }

    const args = text.split(/\s+/);
    const cmdName = args[0]?.toLowerCase() || '';

    for (const cmd of this.registry.getAll(msg.isOwner || false, finalIsSubBot)) {
      if (cmd.usePrefix === false && cmd.execute) {
        if (this.getCommandNames(cmd).includes(cmdName)) {
          const cmdContext: any = {
            ...context,
            text: args.slice(1).join(' '),
            args: args.slice(1),
            command: cmdName,
            prefix: ''
          };
          return await this.executor.execute(cmd, msg, cmdContext, ctx, (cmd as any).__filePath);
        }
      }
    }

    return false;
  }

  private async getGroupParticipants(msg: Message, ctx: any): Promise<any[]> {
    if (!msg.isGroup) return [];
    try {
      const groupMetadata = await ctx.sock.groupMetadata(msg.from);
      return groupMetadata.participants || [];
    } catch {
      return [];
    }
  }

  private async runBeforeHandlers(msg: Message, context: any): Promise<boolean> {
    for (const handler of this.beforeHandlers) {
      try {
        const result = await handler(msg, context, this.bot);
        if (result === true) return true;
      } catch (error: any) {
        UI.error(`Before handler error: ${error.message}`);
        UI.line();
      }
    }
    return false;
  }

  private async runAfterHandlers(msg: Message, extracted: any, context: any, bot?: any): Promise<void> {
    for (const handler of this.afterHandlers) {
      try {
        await handler(msg, { command: extracted.command, args: extracted.args, cmdContext: context }, bot ?? this.bot);
      } catch (error: any) {
        UI.error(`After handler error: ${error.message}`);
        UI.line();
      }
    }
  }

  private getCommandNames(cmd: CommandOptions): string[] {
    const names: string[] = [];
    if (cmd.command && !(cmd.command instanceof RegExp)) {
      const cmdNames = Array.isArray(cmd.command) ? cmd.command : [cmd.command];
      names.push(...cmdNames);
    }
    if (cmd.name) names.push(cmd.name);
    if (cmd.aliases) names.push(...cmd.aliases);
    return names.map(n => n.toLowerCase());
  }

  async loadFile(filePath: string, forceReload: boolean = false): Promise<void> {
    const normalizedPath = resolve(filePath);

    if (!forceReload && sharedLoadedPaths.has(normalizedPath)) return;

    const commands = await this.loader.loadFile(normalizedPath, forceReload);
    if (!commands) return;

    const cmdArray = Array.isArray(commands) ? commands : [commands];
    for (const cmd of cmdArray) {
      if (typeof cmd === 'function') {
        (cmd as any).__filePath = normalizedPath;
        this.before(cmd as Handler);
      } else if (cmd && (cmd as CommandOptions).execute) {
        (cmd as any).__filePath = normalizedPath;
        this.register(cmd as CommandOptions);
      }
    }
    sharedLoadedPaths.add(normalizedPath);
  }

  async loadDirectory(commandsPath: string): Promise<void> {
    const absolutePath = this.resolvePath(commandsPath);
    if (sharedLoadedPaths.has(absolutePath)) return;

    const scanDir = async (dir: string): Promise<void> => {
      try {
        const items = await readdir(dir, { withFileTypes: true });
        for (const item of items) {
          const fullPath = join(dir, item.name);
          if (item.isDirectory()) {
            await scanDir(fullPath);
          } else if (item.isFile()) {
            const ext = extname(item.name).toLowerCase().slice(1);
            if (ext && VALID_EXTENSIONS.includes(ext)) {
              await this.loadFile(fullPath);
            }
          }
        }
      } catch (error: any) {
        UI.error(`Failed to scan ${dir}: ${error.message}`);
        UI.line();
      }
    };

    await scanDir(absolutePath);
    sharedLoadedPaths.add(absolutePath);
  }

  startWatching(commandsPath: string): void {
    if (this.watcherStarted) return;
    this.watcher.start(commandsPath);
    this.watcherStarted = true;
  }

  stopWatcher(): void {
    if (this.watcherStarted) {
      this.watcher.stop();
      this.watcherStarted = false;
    }
  }

  private async handleFileChange(filePath: string, event: 'add' | 'change' | 'unlink'): Promise<void> {
    const normalizedPath = resolve(filePath);

    sharedLoadedPaths.delete(normalizedPath);
    sharedLoadedPaths.delete(dirname(normalizedPath));

    if (event === 'unlink') {
      this.unloadFile(filePath);
      UI.info(`Command unloaded from: ${normalizedPath}`);
    } else if (event === 'add' || event === 'change') {
      await new Promise(r => setTimeout(r, 500));
      this.unloadFile(filePath);
      await this.loadFile(filePath, true);
      UI.info(`Command ${event === 'add' ? 'loaded' : 'reloaded'} from: ${normalizedPath}`);
    }
  }

  private unloadFile(filePath: string): void {
    const normalizedPath = resolve(filePath);
    this.registry.unregisterByFile(normalizedPath);
    sharedLoadedPaths.delete(normalizedPath);

    this.beforeHandlers = this.beforeHandlers.filter(h => {
      const hp = (h as any).__filePath;
      return !hp || resolve(hp) !== normalizedPath;
    });

    this.afterHandlers = this.afterHandlers.filter(h => {
      const hp = (h as any).__filePath;
      return !hp || resolve(hp) !== normalizedPath;
    });

    this.loader.clearCache(normalizedPath);
  }

  private resolvePath(givenPath: string): string {
    if (isAbsolute(givenPath)) return givenPath;
    const candidates = [resolve(process.cwd(), givenPath), resolve(__dirname, givenPath)];
    for (const p of candidates) { if (existsSync(p)) return p; }
    return resolve(process.cwd(), givenPath);
  }

  clearCooldowns(userId?: string): void { this.executor.getCooldownManager().clear(userId); }

  getStats() {
    return {
      ...this.registry.getStats(),
      middlewares: this.middleware.length,
      beforeHandlers: this.beforeHandlers.length,
      afterHandlers: this.afterHandlers.length,
      loadedPaths: sharedLoadedPaths.size,
    };
  }

  abortUserCommands(userId: string): void {}

  destroy(): void {
    this.stopWatcher();
    this.executor.destroy();
    this.middleware.clear();
    this.beforeHandlers = [];
    this.afterHandlers = [];
    this.loader.clearCache();
  }

  resetLoadedPaths(): void { sharedLoadedPaths.clear(); }

  static resetSharedCache(): void {
    sharedLoadedPaths.clear();
  }

  static isPathLoaded(path: string): boolean { return sharedLoadedPaths.has(path); }
  static stopGlobalWatcher(): void { CommandFileWatcher.stopGlobalWatcher(); }
}

export async function loadCommandsFromPath(commandsPath: string, commandSystem?: CommandSystem): Promise<CommandOptions[]> {
  if (!commandSystem) return [];
  await commandSystem.loadDirectory(commandsPath);
  commandSystem.startWatching(commandsPath);
  return commandSystem.getAll();
}

export { errorCmd, logError };