function createClient(prefix: keyof typeof endpoints) {
  return Object.fromEntries(
    Object.entries(endpoints[prefix]).map(([path, config]) => {
      return [
        config.name,
        async (params: Record<string, string> = {}) => {
          if (config.params) {
            for (const p of config.params) {
              if (!params[p]) throw new Error(`Missing: ${p}`);
            }
          }
          
          const { data } = await apiClient({
            method: config.method || 'GET',
            url: path,
            params: params
          });
          return data;
        }
      ];
    })
  );
}

export const api = {
  download: createClient('download'),
  search: createClient('search'),
  tools: createClient('tools')
};