import { Message } from "../types/types.js";

const ACCESS_MESSAGES: Record<string, string | ((t: number) => string)> = {
  disabled:  "⚠️ *This command is currently disabled*",
  owner:     "❌ *This command is for owner only*",
  group:     "👥 *This command is for groups only*",
  admin:     "*⚡ This command is for admin only*",
  private:   "🔒 *This command is for private chats only*",
  botAdmin:  "🤖 *Bot needs to be admin to use this command*",
  noSub:     "🎪 *This is only for the main bot*",
  cooldown:  (t: number) => `⏳ Please wait ${t} seconds before using this command again.`,
  error:     "❌ *An error occurred during execution*",
};

function resolveMessage(checkType: string, args: any[]): string | null {
  const entry = ACCESS_MESSAGES[checkType];
  if (!entry) return null;
  return typeof entry === "function" ? entry(args[0]) : entry;
}

async function sendNotification(bot: any, msg: Message, text: string): Promise<void> {
  const sock = bot.sock;
  if (!sock) return;

  const isSubBot = bot.isSubBot === true || bot.constructor?.name === "SubBot";
  const config   = bot.config ?? (isSubBot ? bot.globalConfig : null);
  const botName  = config?.info?.nameBot ?? (isSubBot ? "Sub Bot" : "WhatsApp Bot");

  try {
    if (typeof sock.msgUrl === "function") {
      await sock.msgUrl(msg.chat, text, {
        img:   "https://files.catbox.moe/hm9iq4.jpg",
        title: botName,
        big:   false,
      });
    } else {
      await sock.sendMessage(msg.chat, { text });
    }
  } catch {
    await sock.sendMessage(msg.chat, { text });
  }
}

export async function cmdControl(
  bot: any,
  msg: Message,
  checkType: string,
  ...args: any[]
): Promise<void> {
  if (bot.userAccessHandler) {
    const result = await bot.userAccessHandler(msg, checkType, ...args);
    if (result !== undefined && result !== null) return;
  }

  const message = resolveMessage(checkType, args);
  if (message) await sendNotification(bot, msg, message);
}
