import { UI, color } from "./index.js";
import { loadCommandsFromPath, CommandSystem } from "../r-enhancers/index.js";

const loadedPaths = new Set<string>();

const loadCommands = async (OOP: any) => {
    try {
      if (!OOP.commandSystem) {
        throw new Error('CommandSystem not initialized');
      }
      
      const commandsPath = OOP.config.commandsPath;
      
      if (loadedPaths.has(commandsPath)) {
        if (OOP.config.showLogs) {
        //  UI.info(`📦 Commands already loaded - ${commandsPath}`);
        }
        return;
      }
      
      await loadCommandsFromPath(commandsPath, OOP.commandSystem);
      
      loadedPaths.add(commandsPath);
      
      const commandsCount = OOP.commandSystem.getStats().total;
      
      if (OOP.config.showLogs) {
        console.log(color(`       _,    _   _    ,_
  .o888P     Y8o8Y     Y888o.
 d88888      88888      88888b
d888888b_  _d88888b_  _d888888b
8888888888888888888888888888888
8888888888888888888888888888888
YJGS8P"Y888P"Y888P"Y888P"Y8888P
 Y888   '8'   Y8P   '8'   888Y
  '8o          V          o8'
    \`                     \``, "red"));
        UI.line();
        UI.info(`Loaded (${commandsCount}) commands in "${commandsPath}"`);
        UI.info(`Name Bot: ${OOP.config.info?.nameBot || "WhatsApp Bot"}`);
        UI.line();
      }
    } catch (error: any) {
      setTimeout(async () => {
        UI.error(`[${new Date().toLocaleTimeString()}] Error loading Commands: ${error.message}`);
        UI.line();
      }, 4000);
    }
};

export { loadCommands };