import { Level } from 'level';
import { initAuthCreds, BufferJSON, proto } from '@whiskeysockets/baileys';
import type { AuthenticationCreds } from '@whiskeysockets/baileys';
import { randomBytes } from 'node:crypto';
import { gzip, gunzip } from 'node:zlib';
import { promisify } from 'node:util';

const gzipAsync = promisify(gzip);
const gunzipAsync = promisify(gunzip);

// ─── Constants ────────────────────────────────────────────────────────────────
const EPHEMERAL_PREFIXES = [
  'pre-key-',
  'sender-key-',
  'sender-key-memory-',
  'app-state-sync-version-',
  'app-state-sync-key-',
] as const;

const KEEP_LAST_EPHEMERAL = 60;
const PRUNE_AFTER_WRITES = 100;
const NUM_SHARDS = 8;
const CACHE_TTL = 300_000; // 5min
const FLUSH_DELAY = 50;
const COMPRESS_AT = 10_240; // 10KB
const MAX_RETRIES = 3;
const RETRY_DELAY_MS = 500;

// ─── Logger ───────────────────────────────────────────────────────────────────
const log = {
  info: (msg: string, meta?: any) => console.log(`[LevelDB] ${msg}`, meta || ''),
  error: (msg: string, err?: any) => console.error(`[LevelDB] ERROR: ${msg}`, err?.message || err || ''),
  warn: (msg: string, meta?: any) => console.warn(`[LevelDB] WARN: ${msg}`, meta || ''),
  debug: (msg: string, meta?: any) => process.env.DEBUG && console.debug(`[LevelDB] ${msg}`, meta || ''),
};

// ─── LevelDBManager ──────────────────────────────────────────────────────────
class LevelDBManager {
  private shards = new Map<number, Level<string, string>>();
  private cache = new Map<string, { data: any; exp: number }>();
  private pending = new Map<string, string>();
  private writeCounters = new Map<string, number>();
  private flushTimer: NodeJS.Timeout | null = null;
  private cleanupInterval: NodeJS.Timeout | null = null;
  private globalConfig: any = null;
  private flushing = false;
  private metrics = {
    hits: 0,
    misses: 0,
    reads: 0,
    writes: 0,
    fails: 0,
  };

  constructor() {
    this.startCleanup();
  }

  private startCleanup(): void {
    this.cleanupInterval = setInterval(() => {
      const now = Date.now();
      let cleaned = 0;
      for (const [key, { exp }] of this.cache) {
        if (exp < now) {
          this.cache.delete(key);
          cleaned++;
        }
      }
      if (cleaned > 0) log.debug(`Cache: cleaned ${cleaned} expired entries`);
    }, 60_000);
  }

  private shardId(key: string): number {
    let h = 0;
    for (let i = 0; i < key.length; i++) {
      h = ((h << 5) - h) + key.charCodeAt(i);
      h |= 0;
    }
    return Math.abs(h) % NUM_SHARDS;
  }

  private async getDB(sid: number): Promise<Level<string, string>> {
    if (!this.shards.has(sid)) {
      const db = new Level<string, string>(`./sub/shard-${sid}`, { valueEncoding: 'utf8' });
      await db.open();
      this.shards.set(sid, db);
    }
    return this.shards.get(sid)!;
  }

  private async encode(val: any): Promise<string> {
    const str = JSON.stringify(val, BufferJSON.replacer);
    if (str.length > COMPRESS_AT) {
      const buf = await gzipAsync(str);
      return 'gz:' + buf.toString('base64');
    }
    return str;
  }

  private async decode(raw: string): Promise<any> {
    if (raw.startsWith('gz:')) {
      const buf = Buffer.from(raw.slice(3), 'base64');
      const out = await gunzipAsync(buf);
      return JSON.parse(out.toString(), BufferJSON.reviver);
    }
    return JSON.parse(raw, BufferJSON.reviver);
  }

  private async batchRetry(ops: any[], sid: number, tries = MAX_RETRIES): Promise<void> {
    for (let i = 0; i < tries; i++) {
      try {
        await (await this.getDB(sid)).batch(ops);
        return;
      } catch (err) {
        if (i === tries - 1) throw err;
        log.warn(`Batch retry ${i + 1}/${tries}`, err);
        await new Promise(r => setTimeout(r, RETRY_DELAY_MS * (i + 1)));
      }
    }
  }

  async get(key: string): Promise<any> {
    this.metrics.reads++;

    if (this.pending.has(key)) {
      this.metrics.hits++;
      return this.decode(this.pending.get(key)!);
    }

    const cached = this.cache.get(key);
    if (cached && cached.exp > Date.now()) {
      this.metrics.hits++;
      return cached.data;
    }

    this.metrics.misses++;
    try {
      const raw = await (await this.getDB(this.shardId(key))).get(key);
      const data = await this.decode(raw);
      this.cache.set(key, { data, exp: Date.now() + CACHE_TTL });
      return data;
    } catch {
      return null;
    }
  }

  async put(key: string, val: any): Promise<void> {
    this.metrics.writes++;
    const enc = await this.encode(val);
    this.cache.set(key, { data: val, exp: Date.now() + CACHE_TTL });
    this.pending.set(key, enc);

    // Counter-based ephemeral pruning
    const ephType = EPHEMERAL_PREFIXES.find(p => key.includes(p));
    if (ephType) {
      const botId = key.split('::')[0];
      const counterKey = `${botId}::${ephType}`;
      const count = (this.writeCounters.get(counterKey) ?? 0) + 1;
      if (count >= PRUNE_AFTER_WRITES) {
        this.writeCounters.delete(counterKey);
        setImmediate(() => this.pruneEphemeralType(botId, ephType));
      } else {
        this.writeCounters.set(counterKey, count);
      }
    }

    this.scheduleFlush();
  }

  private scheduleFlush(): void {
    if (!this.flushTimer) {
      this.flushTimer = setTimeout(() => this.flush(), FLUSH_DELAY);
    }
  }

  async del(key: string): Promise<void> {
    this.cache.delete(key);
    this.pending.delete(key);
    await (await this.getDB(this.shardId(key))).del(key).catch(() => {});
  }

  async deletePrefix(prefix: string, confirm = false): Promise<void> {
    if (!confirm) throw new Error('deletePrefix requires confirm=true');

    // Group deletes by shard to batch them
    const byShard = new Map<number, string[]>();
    for (let i = 0; i < NUM_SHARDS; i++) {
      const db = await this.getDB(i);
      for await (const key of db.keys({ gte: prefix, lte: prefix + '\xFF' })) {
        if (!key.startsWith(prefix)) break;
        this.cache.delete(key);
        this.pending.delete(key);
        if (!byShard.has(i)) byShard.set(i, []);
        byShard.get(i)!.push(key);
      }
    }

    await Promise.all(
      [...byShard].map(async ([sid, keys]) => {
        const ops = keys.map(k => ({ type: 'del' as const, key: k }));
        await this.batchRetry(ops, sid);
      })
    );
  }

  async flush(): Promise<void> {
    this.flushTimer = null;
    if (this.pending.size === 0) return;
    if (this.flushing) {
      this.scheduleFlush();
      return;
    }

    this.flushing = true;
    const batch = this.pending;
    this.pending = new Map();

    const byShard = new Map<number, Array<{ type: 'put'; key: string; value: string }>>();
    for (const [key, val] of batch) {
      const sid = this.shardId(key);
      if (!byShard.has(sid)) byShard.set(sid, []);
      byShard.get(sid)!.push({ type: 'put', key, value: val });
    }

    await Promise.all(
      [...byShard].map(async ([sid, ops]) => {
        try {
          await this.batchRetry(ops, sid);
        } catch (err) {
          this.metrics.fails++;
          log.error(`Batch write failed for shard ${sid}`, err);
          for (const op of ops) {
            if (!this.pending.has(op.key)) this.pending.set(op.key, op.value);
          }
          this.scheduleFlush();
        }
      })
    );

    this.flushing = false;
  }

  async *iterateAll(): AsyncGenerator<[string, string]> {
    for (let i = 0; i < NUM_SHARDS; i++) {
      const db = await this.getDB(i);
      for await (const entry of db.iterator()) yield entry;
    }
  }

  private async pruneEphemeralType(botId: string, keyType: string): Promise<void> {
    const fullPrefix = `${botId}::${keyType}`;
    const keysByShard = new Map<number, string[]>();

    for (let i = 0; i < NUM_SHARDS; i++) {
      const db = await this.getDB(i);
      for await (const key of db.keys({ gte: fullPrefix, lte: fullPrefix + '\xFF' })) {
        if (!key.startsWith(fullPrefix)) break;
        if (!keysByShard.has(i)) keysByShard.set(i, []);
        keysByShard.get(i)!.push(key);
      }
    }

    const allKeys = [...keysByShard.values()].flat();
    if (allKeys.length <= KEEP_LAST_EPHEMERAL) return;

    allKeys.sort((a, b) => {
      const extractTs = (k: string): number => {
        const parts = k.split('-');
        const ts = parseInt(parts[parts.length - 1]);
        return isNaN(ts) ? 0 : ts;
      };
      return extractTs(a) - extractTs(b);
    });

    const toDelete = new Set(allKeys.slice(0, allKeys.length - KEEP_LAST_EPHEMERAL));

    // Batch deletes per shard
    await Promise.all(
      [...keysByShard].map(async ([sid, keys]) => {
        const ops = keys
          .filter(k => toDelete.has(k))
          .map(k => {
            this.cache.delete(k);
            this.pending.delete(k);
            return { type: 'del' as const, key: k };
          });
        if (ops.length) await this.batchRetry(ops, sid);
      })
    );

    log.debug(`Pruned ${toDelete.size} ${keyType} keys for bot ${botId}`);
  }

  async pruneBot(botId: string): Promise<Record<string, number>> {
    const deleted: Record<string, number> = {};
    await Promise.all(
      EPHEMERAL_PREFIXES.map(async keyType => {
        const prefix = `${botId}::${keyType}`;
        const before = await this.countPrefix(prefix);
        await this.pruneEphemeralType(botId, keyType);
        const after = await this.countPrefix(prefix);
        const diff = before - after;
        if (diff > 0) deleted[keyType] = diff;
      })
    );
    return deleted;
  }

  private async countPrefix(prefix: string): Promise<number> {
    let n = 0;
    for (let i = 0; i < NUM_SHARDS; i++) {
      const db = await this.getDB(i);
      for await (const key of db.keys({ gte: prefix, lte: prefix + '\xFF' })) {
        if (!key.startsWith(prefix)) break;
        n++;
      }
    }
    return n;
  }

  async storageStats(): Promise<{ total: number; byType: Record<string, number>; bytes: number }> {
    let total = 0, bytes = 0;
    const byType: Record<string, number> = {};
    for await (const [key, val] of this.iterateAll()) {
      total++;
      bytes += key.length + (val?.length ?? 0);
      const suffix = EPHEMERAL_PREFIXES.find(p => key.includes(p)) ?? 'other';
      byType[suffix] = (byType[suffix] ?? 0) + 1;
    }
    return { total, byType, bytes };
  }

  getMetrics() {
    return {
      ...this.metrics,
      hitRate: this.metrics.hits / (this.metrics.reads || 1),
      cacheSize: this.cache.size,
      pending: this.pending.size,
    };
  }

  async close(timeout = 5000): Promise<void> {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
      this.cleanupInterval = null;
    }

    await Promise.race([this.flush(), new Promise(r => setTimeout(r, timeout))]);
    await Promise.all([...this.shards.values()].map(db => db.close()));

    this.shards.clear();
    this.cache.clear();
    this.writeCounters.clear();
  }

  // ─── Global Config Methods ────────────────────────────────────────────────
  async getGlobalConfig(): Promise<any> {
    if (this.globalConfig) return this.globalConfig;
    const cfg = await this.get('::global-config');
    this.globalConfig = cfg;
    return cfg;
  }

  async setGlobalConfig(cfg: any): Promise<void> {
    this.globalConfig = cfg;
    await this.put('::global-config', cfg);
  }

  invalidateGlobalConfigCache(): void {
    this.globalConfig = null;
  }
}

// ─── Singleton ───────────────────────────────────────────────────────────────
const db = new LevelDBManager();

export const getDB = () => db;
export const closeDB = () => db.close();
export const pruneBot = (id: string) => db.pruneBot(id);
export const storageStats = () => db.storageStats();
export const getMetrics = () => db.getMetrics();

export const uid = () => randomBytes(6).toString('hex');

// ─── hasAuthData Helper ──────────────────────────────────────────────────────
export async function hasAuthData(botId: string): Promise<boolean> {
  try {
    const creds = await db.get(`${botId}::creds`);
    return !!(creds?.me || creds?.registered);
  } catch {
    return false;
  }
}

// ─── useAuth ─────────────────────────────────────────────────────────────────
export async function useAuth(id: string) {
  const prefix = `${id}::`;
  const get = (k: string) => db.get(prefix + k);
  const set = (k: string, v: any) => db.put(prefix + k, v);
  const del = (k: string) => db.del(prefix + k);

  let creds: AuthenticationCreds = (await get('creds')) ?? initAuthCreds();

  return {
    state: {
      creds,
      keys: {
        get: async (type: string, ids: string[]) => {
          const result: any = {};
          await Promise.all(ids.map(async (kid) => {
            let val = await get(`${type}-${kid}`);
            if (type === 'app-state-sync-key' && val)
              val = proto.Message.AppStateSyncKeyData.fromObject(val);
            result[kid] = val;
          }));
          return result;
        },
        set: async (data: any) => {
          await Promise.all(
            Object.entries(data).flatMap(([type, ids]: [string, any]) =>
              Object.entries(ids).map(([kid, val]) =>
                val ? set(`${type}-${kid}`, val) : del(`${type}-${kid}`)
              )
            )
          );
        },
      },
    },
    save: async () => {
      await set('creds', creds);
    },
    remove: () => db.deletePrefix(prefix, true),
  };
}

// ─── Config Management ────────────────────────────────────────────────────────
export async function saveConfig(id: string, phoneNumber: string): Promise<void> {
  await db.put(`${id}::phone`, phoneNumber);
}

export async function getConfig(id: string): Promise<any> {
  const [globalCfg, phone] = await Promise.all([
    db.getGlobalConfig(),
    db.get(`${id}::phone`),
  ]);

  if (!globalCfg) return { phoneNumber: phone ?? '' };
  return { ...globalCfg, phoneNumber: phone ?? '' };
}

export async function delConfig(id: string): Promise<void> {
  await db.del(`${id}::phone`);
}

export async function setGlobalConfig(cfg: any): Promise<void> {
  await db.setGlobalConfig(cfg);
}

export async function getGlobalConfig(): Promise<any> {
  return db.getGlobalConfig();
}

export async function getAllConfigs(): Promise<Array<{ uid: string; config: any }>> {
  const globalCfg = await db.getGlobalConfig();
  const configs: Array<{ uid: string; config: any }> = [];
  const phonePrefix = '::phone';
  const phoneUids: string[] = [];

  for await (const [key] of db.iterateAll()) {
    if (!key.endsWith(phonePrefix)) continue;
    phoneUids.push(key.slice(0, -phonePrefix.length));
  }

  await Promise.all(
    phoneUids.map(async (uid) => {
      try {
        const phone = await db.get(`${uid}${phonePrefix}`);
        configs.push({
          uid,
          config: { ...globalCfg, phoneNumber: phone ?? '' },
        });
      } catch (err) {
        log.error(`Failed to read config: ${uid}`, err);
      }
    })
  );

  return configs;
}
