import { DisconnectReason } from "@whiskeysockets/baileys";
import { Boom } from "@hapi/boom";
import qrTerminal from "qrcode-terminal";
import { color, UI } from "../utils/index.js";
import MaleBaseOrganization from "../utils/login.js";


const connection_event = async (ctx: any, isNewSession: boolean) => {
  try {

    ctx.sock.ev.on('connection.update', (update: any) => {
      const { connection, lastDisconnect, qr } = update;
      const { config } = ctx;
      const { showLogs, printQR, autoReconnect, maxReconnectAttempts, reconnectDelay, onConnected, onDisconnected } = config;

      if (qr && printQR && showLogs) {
        UI.line();
        UI.done('Scan QR code to login ↓');
        qrTerminal.generate(qr, { small: true });
        UI.line();
      }

      if (connection === 'close') {
        ctx.reconnectTimeout && clearTimeout(ctx.reconnectTimeout);
        
        const error = lastDisconnect?.error as Boom;
        const statusCode = error?.output?.statusCode;

        switch (statusCode) {
          case DisconnectReason.loggedOut:
            showLogs && UI.error(' Session logged out. Please re-pair the device.');
            ctx.isRunning = false;
            onDisconnected?.();
            return;

          case DisconnectReason.connectionClosed:
            showLogs && UI.warn(' Connection closed unexpectedly');
            break;
            
          case DisconnectReason.connectionLost:
            showLogs && UI.warn(' Connection lost');
            break;
            
          case DisconnectReason.connectionReplaced:
            showLogs && UI.warn(' Connection replaced by another session');
            ctx.isRunning = false;
            onDisconnected?.();
            return;
            
          case DisconnectReason.multideviceMismatch:
            showLogs && UI.error(' Multi-device mismatch. Please re-pair.');
            ctx.isRunning = false;
            onDisconnected?.();
            return;
            
          case DisconnectReason.forbidden:
            showLogs && UI.error(' Forbidden access');
            ctx.isRunning = false;
            onDisconnected?.();
            return;
            
          case DisconnectReason.unavailableService:
            showLogs && UI.error(' Service unavailable');
            break;
            
          case DisconnectReason.badSession:
            showLogs && UI.error(' Bad session');
            ctx.isRunning = false;
            onDisconnected?.();
            return;
            
          case DisconnectReason.restartRequired:
            showLogs && UI.info(' Restart required');
            ctx.restart(true);
            return;
            
          default:
            if (error?.message?.includes('timed out') || error?.message?.includes('timeout')) {
              showLogs && UI.warn(' Connection timed out');
            } else {
              showLogs && UI.error(` Unknown disconnect reason: ${statusCode}`);
            }
        }

        if (autoReconnect && ctx.reconnectAttempts < maxReconnectAttempts) {
          ctx.reconnectAttempts++;
          showLogs && UI.loading(`Reconnecting... (${ctx.reconnectAttempts} ~ ${maxReconnectAttempts})`);
          
          ctx.reconnectTimeout && clearTimeout(ctx.reconnectTimeout);
          ctx.reconnectTimeout = setTimeout(() => {
            ctx.isRunning = false;
            ctx.restart(true);
          }, reconnectDelay);
        } else {
          ctx.isRunning = false;
          onDisconnected?.();
        }
      }

      if (connection === 'open') {
        ctx.reconnectAttempts = 0;
        ctx.reconnectTimeout && clearTimeout(ctx.reconnectTimeout);

        setTimeout(async () => {
        onConnected?.();
        await ctx.sock.KeysMessageWA()
        await ctx.sock. uploadPreKeysToServerIfRequired()
        await MaleBaseOrganization(ctx)
        }, 2000)
        if (showLogs) {
          UI.clear();
          UI.random(`${ctx.config.info.nameBot || "WhatsApp Bot"} started successfully`);
          console.log(`      ______ ______
    _/      Y      \_
   // ~~ ~~ | ~~ ~  \\
  // ~ ~ ~~ | ~~~ ~~ \\      Original ${ctx.config.info.nameBot || "WhatsApp Bot"}
 //________.|.________\\     Created by: ${color("@veni_xov", "yellow")}
\`----------\`-'----------'`)
          UI.line()
          UI.info('Bot Engine    : whatsappy')
          UI.info('Backend       : Node.js & Type Script')
          UI.info(`Runtime       : ${process.version}`);
          UI.info(`Platform      : ${process.platform}`);
          UI.line()
        }
      }
    });
  } catch (error: any) {
    if (!ctx.config.onError) console.error(error.message)
    typeof ctx.config?.onError === 'function' && ctx.config.onError(error);
  }
};

export default connection_event;