import { GroupEvent } from "../types/types.js";

const group_event = (bot: any) => {
  let ready = false;
  setTimeout(() => { ready = true; }, 5000);

  bot.sock.ev.on('group-participants.update', async (data: any) => {
    if (!ready) return;
    
    try {
      const meta: any = await bot.sock.groupMetadata(data.id);
      const authorPart = meta.participants.find((x: any) => x.id === data.author);
      const authorPhone = authorPart?.phoneNumber || data.author;
      
      let authorPp, userPp;
      try { if (data.author) authorPp = await bot.sock.profilePictureUrl(data.author, 'image'); } catch {}
      try { if (data.participants?.[0]?.id) userPp = await bot.sock.profilePictureUrl(data.participants[0].id, 'image'); } catch {}
      
      const ev: GroupEvent = {
        id: data.id, chat: data.id,
        userUrl: userPp || null, participants: data.participants,
        action: data.action, author: authorPhone, authorUrl: authorPp,
        timestamp: new Date()
      };
      
      await bot.groupControl(ev, data.action);
    } catch (e: any) {
      console.error("group_event error:", e.message);
    }
  });
};

export default group_event;