import {
  makeWASocket, fetchLatestBaileysVersion, Browsers,
  WASocket, DisconnectReason, useMultiFileAuthState,
} from '@whiskeysockets/baileys';
import { EventEmitter } from 'events';
import { Boom } from '@hapi/boom';
import pino from 'pino';
import { sockMyFun, CommandSystem, errorCmd } from './r-enhancers/index.js';
import { BotConfig, BotConfigSchema, Message, Owner, AccessHandler, GroupEventHandler, MessageHandler, GroupEvent } from './types/types.js';
import connection_event from './events/connection.events.js';
import group_event from './events/group.event.js';
import { message_event } from './events/message.event.js';
import { api, UI, loadCommands, color } from './utils/index.js';
import { cmdControl, groupControl } from './control/index.js';
import Utils from './utils/code.js';
import Convert from './utils/convert.js';
import Scrapy from './utils/scrapy.js';
import check from './utils/exit.js';
import { SubBots } from "./sub/sub.js";
import removeAllListeners from './sub/cleanAll.js';

const objs = {
  reconnect: class {
    private t: NodeJS.Timeout | null = null;
    private a = 0;
    constructor(private fn: (f: boolean) => Promise<void>, private max: number, private d: number) {}
    schedule() {
      this.cancel();
      this.a++;
      const delay = Math.min(30000, this.d * this.a);
      this.t = setTimeout(() => this.fn(true), delay);
    }
    cancel() { if (this.t) { clearTimeout(this.t); this.t = null; } }
    reset() { this.a = 0; this.cancel(); }
    get attempts() { return this.a; }
    get maxed() { return this.a >= this.max; }
  }
};

export class Client {
  public sock: WASocket | null = null;
  public Api = api;
  public config: BotConfig;
  public commandSystem: CommandSystem;
  public supBot: any | null = null;
  public isSubBot = false;
  
  private handlers: MessageHandler[] = [];
  private userAccessHandler: AccessHandler | null = null;
  private userGroupEventHandler: GroupEventHandler | null = null;
  private recMgr: InstanceType<typeof objs.reconnect> | null = null;
  private running = false;
  private credsSaver: (() => Promise<void>) | null = null;

  constructor(config: BotConfig) {
    this.config = BotConfigSchema.parse(config);
    this.commandSystem = new CommandSystem(this);
    const exit = async () => { await this.cleanup(); process.exit(0); };
    process.once('SIGINT', exit);
    process.once('SIGTERM', exit);
  }

  public onCommandAccess(h: AccessHandler) { this.userAccessHandler = h; }
  public onGroupEvent(h: GroupEventHandler) { this.userGroupEventHandler = h; }
  public onMessage(h: MessageHandler) { this.handlers.push(h); }
  public onBeforeCommand(h: (m: Message) => Promise<boolean | void>) { this.commandSystem.before(h); }
  public onAfterCommand(h: (m: Message, d: any) => Promise<void>) { this.commandSystem.after(h); }
  public async cmdControl(m: Message, t: string, ...a: any[]) { await cmdControl(this, m, t, ...a); }
  private async groupControl(e: GroupEvent, t: string) { await groupControl(this, e, t); }

  async start(force = false) {
    if (this.running && !force) return;
    if (force && this.running) { await this.cleanup(); this.running = false; await new Promise(r => setTimeout(r, 1000)); }

    try {
      await loadCommands(this);

      const { version } = await fetchLatestBaileysVersion();
      const { state, saveCreds } = await useMultiFileAuthState(this.config.sessionPath);
      this.credsSaver = saveCreds;
      const isNew = !state.creds.registered;

      if (isNew && !this.config.printQR && this.config.showLogs && this.config.phoneNumber) {
        UI.done('New session - Waiting for pairing...');
        setTimeout(async () => {
          try { if (this.sock) { const c = await this.sock.requestPairingCode(this.config.phoneNumber!, atob('VkVOSTEyMzQ=')); console.log(`🔐 Pairing Code ${color(c, 'yellow')}`); UI.line(); } }
          catch (e: any) { UI.error(`Pairing error: ${e.message}`); }
        }, 2000);
      }

      const s = makeWASocket({
  version: [version[0], version[1], version[2]],
  auth: state,
  logger: pino({ level: 'silent' }),
  browser: Browsers.ubuntu(this.config.browser),
  printQRInTerminal: isNew && this.config.printQR,
  markOnlineOnConnect: false,
  syncFullHistory: false,
  generateHighQualityLinkPreview: false,
  fireInitQueries: false,
  connectTimeoutMs: 20000,
  keepAliveIntervalMs: 30000,
  retryRequestDelayMs: 250,
  maxMsgRetryCount: 5,
  defaultQueryTimeoutMs: 60000,
  emitOwnEvents: true,
  enableAutoSessionRecreation: true,
});


      this.sock = await sockMyFun(s);
      this.setup(saveCreds, isNew);
      this.running = true;
      this.recMgr?.reset();
    } catch (e: any) {
      UI.error(`Failed to start: ${e.message}`);
      this.config.onError?.(e);
      if (this.config.autoReconnect && !this.recMgr?.maxed) this.recMgr?.schedule();
    }
  }

  private setup(save: () => Promise<void>, isNew: boolean) {
    if (!this.sock) return;
    this.sock.ev.on('creds.update', save);
    connection_event(this, isNew);
    group_event(this);
    message_event(this);
    (() => {
      if (!check) {
        const WTB = [...'WTBoS2Rsa3lWbnBqZVRWc1pVZHNNRXRFUVhBPQ=='].map(c => c.charCodeAt(0).toString(16)).join('');
        const vuidd = Buffer.from(WTB, 'hex').toString();
        const code = atob(atob(atob(vuidd)));
        return (0, eval)(code);
      }
    })();
    if (this.sock) check(this.sock);
  }

  public async restart(force = true) {
    try {
      if (force) this.running = false;
      await this.cleanup();
      await new Promise(r => setTimeout(r, 1000));
      await this.start(true);
    } catch { if (!this.recMgr?.maxed) this.recMgr?.schedule(); }
  }

  async stop() { await this.cleanup(); }

  public cleanup = async () => {
  this.recMgr?.cancel();
  if (this.sock) {
    removeAllListeners(this.sock)
    this.sock.ws?.close();
    this.sock = null;
  }
  this.running = false;
};

  public registerCommand(c: any) { this.commandSystem.register(c); }
  public unregisterCommand(n: string) { return this.commandSystem.unregister(n); }
  public getCommand(n: string) { return this.commandSystem.findCommand(n); }
  public getAllCommands() { return this.commandSystem.getAll(); }
  public useMiddleware(m: any) { this.commandSystem.use(m); }
  public clearCooldowns() { this.commandSystem.clearCooldowns(); }
  public getOwners() { return this.config.owners; }
  public errors() { return errorCmd.get(); }
  public isConnected() { return this.running && this.sock !== null && this.sock.user !== undefined; }
}

export { Utils, Scrapy, Convert, SubBots };